abstract class Device { public string Id; public string Name; public abstract string GetStatus(); }

class TempSensor : Device
{ public override string GetStatus() { return $"{Name}: 正常"; } }

class Motor : Device
{ public override string GetStatus() { return $"{Name}: 停止"; } }

var devices = new List<Device>();
var t = new TempSensor { Id="T1", Name="温度传感器" };
var m = new Motor { Id="M1", Name="电机" };
devices.Add(t); devices.Add(m);
foreach (var d in devices) Print(d.GetStatus());
